INSERT INTO public.courts (name, address, city, district, lat, lng, rating, rating_count, phone, google_maps_url, booking_url, place_id, thumbnail_url, images, opening_hours, reviews_data, popular_times, amenities, tags, highlight, hours_open, hours_close) VALUES ('Picklehead My Khe Beach - Pickleball Club', '84 Chế Lan Viên, Bắc Mỹ An, Ngũ Hành Sơn, Đà Nẵng 550000, Vietnam', 'Da Nang', 'Bắc Mỹ An, Ngu Hanh Son', 16.040253, 108.24652, 5.0, 125, '+84 797 430 999', 'https://www.google.com/maps/place/Picklehead+My+Khe+Beach+-+Pickleball+Club/data=!4m7!3m6!1s0x3142170053dbd1b9:0xc5a1b349fb6f9516!8m2!3d16.0402533!4d108.2465203!16s%2Fg%2F11lnt2z3d3!19sChIJudHbUwAXQjERFpVv-0mzocU?authuser=0&hl=en&rclk=1', 'https://datlich.alobo.vn/san/sport_picklehead_my_khe_beach', 'ChIJudHbUwAXQjERFpVv-0mzocU', 'https://lh3.googleusercontent.com/gps-cs-s/APNQkAGuU38Nf6AQmXm9KzbbHL3mfvpiYn1SwS8BMSGujzarv4OH1UC9Yes92BjYZFI4cvqbbsG2TyOMtwoiXP0q0LtcQX3orrk8WTZBPHmcHWP8LMxbCvMMZTMjdJxYZj5W0RJ3QY5e8g=w408-h305-k-no', '[{"title": "All", "image": "https://lh3.googleusercontent.com/gps-cs-s/APNQkAGuU38Nf6AQmXm9KzbbHL3mfvpiYn1SwS8BMSGujzarv4OH1UC9Yes92BjYZFI4cvqbbsG2TyOMtwoiXP0q0LtcQX3orrk8WTZBPHmcHWP8LMxbCvMMZTMjdJxYZj5W0RJ3QY5e8g=w397-h298-k-no"}, {"title": "Latest", "image": "https://lh3.googleusercontent.com/gps-cs-s/APNQkAGoNWFAwV8Dbecmw60gyQyg4QSjP4ElWLw0J-s8ZMfIHFgzRD5xHbhABdVhavJkBLZvm3bhZ0hqI082mC7W9sYShD_vK79sDIWAt08cGynghXr3gOj6PreToQcqeERdU4a4rmOtU4Iau883=w529-h298-k-no"}, {"title": "Videos", "image": "https://lh3.googleusercontent.com/gps-cs-s/APNQkAH89rT23aej9NYMWCj1Tu5O16XiiCyTP8yIZawBUKWZoY4-IMr9eW92HVtRwKfJu4Y0KBdlAqBluVUj6YhgCw9ZwRyoqT791DAsEvjwaFv75GvLc8elEoe4fqTp5vuttEX5R73S=w224-h398-k-no"}, {"title": "By owner", "image": "https://lh3.googleusercontent.com/gps-cs-s/APNQkAEAWlJlKK6a8U30aDeO4xxBXmQL6_j-noXMc4_1pPUk-laSDeEx6astDhxbQxZCjloqZosFbV0ReSrpfNBqp-MbR9TsqpxsH-ZHFGTLvjJQ7f6P5wUnpMFr7a7KYk9HWEmfg6ao=w446-h298-k-no"}, {"title": "Street View & 360°", "image": "https://streetviewpixels-pa.googleapis.com/v1/thumbnail?panoid=0LeGdkgouzEohJ4PZom4lA&cb_client=maps_sv.tactile.gps&w=224&h=298&yaw=249.20831&pitch=0&thumbfov=100"}]'::jsonb, '{"Friday": ["6:30 a.m.–9:30 p.m."], "Monday": ["6:30 a.m.–9:30 p.m."], "Saturday": ["6:30 a.m.–9:30 p.m."], "Sunday": ["6:30 a.m.–9:30 p.m."], "Thursday": ["6:30 a.m.–9:30 p.m."], "Tuesday": ["6:30 a.m.–9:30 p.m."], "Wednesday": ["6:30 a.m.–9:30 p.m."]}'::jsonb, '[{"Name": "Bai''atur Ridzwan", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjURCzQgM3-VlMttIqCTmah7kBv-W-BB3nfP9ahLrf-fVRJu8qIQAQ=s120-c-rp-mo-ba5-br100", "Rating": 5, "Description": "My wife and I (Malaysian) visited Da Nang in February 2026 to get pickleball coaching with the owner of this court, coach Ho.\n\nFirstly his teaching method is great. He''s fluent in English. I took 8 hours (4 days) of lesson with him. Coach Ho thought me a lot about game mindset and strategy. What I love the most is since both of us are lefties, his coached me how to play specifically as a lefty.\n\nBtw my wife was assigned to another coach at another court, coach Anh and she''s also excellent!\n\nSecondly, the court is well maintained, the surface is good, there''s a friendly ball picker who helped a lot to keep smooth flow of my training.\n\nBecause we had such a great time, we even booked another trip to Da Nang before we went back to Malaysia to continue our lessons here!", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn0v2NnCipjDwSybHzl-W2bDhukeXfVOJqO35KHp6SVQXv-IfpB765LAU3cl8gJxdsAtmZOg8dhj_6nWhYmS3hz317L8-ATA0qTvGQAZS8TkJUBkFiFeOs09OK3h1iZIC9IbNvn7xZzWe3Uw=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn3_uL4ZH4Yke--NQ0pV_-TH0yEZm7oewdFD26OVtyU26z8zO5WMOeJoqLZ6q7Rf9U6R0qrk-OBR3BNqV4FD77q53JeStGB4u_8trTttBPmTFxCMM3jSd6e8-Q6P6o_3fY_WUm5_udzLEIGB=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn3DiBqyyd_Ge_P5lWUrzOBLjV9POtgNJIRDq3VzikLndyxk_ExKZhbgPhcsH4krMBrau4nRm69dzOpCys3dl2zoxop6n403eFwA9B1fg8bTDkhKxw5lI_jciYphpOw5kUtziZmsQ6R6boM=k-no"], "When": "2026-2-28"}, {"Name": "Supamas Chuaynuson", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocJ51HsReqlMY3wb-7aGl8hFj4TaHZZ_Ln2zVDyXiXz_gixieQ=s120-c-rp-mo-br100", "Rating": 5, "Description": "Indoor court so you don’t have to worry about rainy day. Recommend for coaching sessions with coach Ho. He has so many important basics and techniques for tournament to advice and practice. The staff is nice too. He helps you pick up the balls during coaching sessions that is really kind and helpful. Definitely come back to play here again!", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn0ss3Ri1FtjTLe8S-qmCRgdVd7K99rpiFr6mFB0rStuUbQVNgu0cMF6-GGRXRhthIteMAYFesjIbYBytMtt05C7fYfB4FlopZoDvG-JQAbOgv1v6Sjg9tMveq1NedEkPDld6KqaTta4Hwod=k-no"], "When": "2026-1-3"}, {"Name": "Konstantin K", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjW4qUIm2pthzMl51xrUlcNNlqfu96jJ4MJ3TVX4ny5J0XdckGSC=s120-c-rp-mo-br100", "Rating": 5, "Description": "Great place where anyone can dive into the world of pickleball. They host fun social games, and I really enjoy joining the Round Robin sessions for DUPR rating. Sometimes we just rent a court and play with friends, which is always a great time.\nWhen I decided to level up my skills, I started training with Ho, and that was a game changer. He quickly spots your weaknesses and helps you fix them with clear, practical guidance. His English is excellent, so every session is easy to understand and super productive.\nYou definitely won’t regret coming here! 🤟", "Images": null, "When": ""}, {"Name": "Noor Ibrahim", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjXOPb3eoxxcd2dkT9URPY0cLulvSBCOqJCSBSi4NsKbZh4ZF_Fqsg=s120-c-rp-mo-ba2-br100", "Rating": 5, "Description": "Had 4 days coaching session here at Picklehead when we were in Danang in February.\nThe court is great..nice surface, selections of drinks they even have fresh coconut.😍\n\nMy husband took private coaching session with coach Ho and another different coach for me - coach Anh (as we are at different level😅)\nBoth coaches are very good.\n\nThis place also have a dedicated ball picker to assist us when we do the drilling.\nWish we have this service in Malaysia! 😂\n\nAlready booked our next coaching and drilling session here in March", "Images": null, "When": ""}, {"Name": "Dawid Kozdraś", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjX5G2W1ZyDsBo48NGuWHMKJWeZyQS9EqUfOUHCcyxe8duRdkhqtkw=s120-c-rp-mo-ba3-br100", "Rating": 5, "Description": "Nguyen Ho is an excellent coach. His training sessions are well-structured, engaging, and focused on details that truly make a difference in your game. He is patient, attentive, and genuinely cares about helping you improve, no matter your current skill level. He takes the time to explain techniques clearly and tailors his coaching to your individual needs. I highly recommend him to beginners as well as players who want to refine and elevate their pickleball skills.", "Images": null, "When": ""}, {"Name": "Hoang Anh Mai", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjU7yifNWhqZW8RvHKziCefXQsAFPkWEnsOuh-SmQh5qWHE1PRRm=s120-c-rp-mo-br100", "Rating": 5, "Description": "Nice and friendly court. Whether you’re beginner or experienced, you’ll enjoy playing here. Relaxed atmosphere and good lighting. Owner and staff are very friendly also!", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn1K1QmxJ6hnsOIIEpo0BX_rIXjf3RdsURbppBbcZgAU69b_wfzjtca--iH7vHGfnkyKSlRkJpFh5UySRBxsN_6Xg2WP150MZCUJhR4s2MlKGdEWeAuUhWIMMXTbKeXoBvRTkFVFL3Iuvf8=k-no"], "When": "2026-1-31"}, {"Name": "차원호", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocIusZuFKRhJYMlD2uzXs5wnAu5JzrJfpoega-GG5YgTJgPj7zU=s120-c-rp-mo-br100", "Rating": 5, "Description": "Whenever I come to Danang, I visit and take lesson from Nguyen Ho who is a great lessoner and player. I strongly recommend this court for the potential picklers.", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn1pAppi7paTesvHn-PEsIcoHzxs7C5ufMwGd1knfWGE8n0Y4u5JVRdAhUXgnrOtzef34ynvgVrCDNQs7NNUoS7HPIRB9HkJ-oXZSM4mkIYS2k745dO0lhqcZdbwMgkvJa32V7u_59kxW1pv=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn0YZEMwyaIb0SBz2gBZ9LvKFDCsH5rv_YhrmxUuEE9Pe-DnSW_gfJl349Z5brKsbKYumIO8GPpKYSfoE572uXy9IAJ5B4RpTQa1VfzXFmHiQOLRuMJZCeuVSk8awCc4sL-ZMo4CRWe1tcRk=k-no"], "When": "2026-1-7"}, {"Name": "mArIn Life with Beach", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjWL3UeYx-rJeURQHCX6vKLxLrFUObWZs32ZkPOY4jg92GXC7Bf_=s120-c-rp-mo-ba6-br100", "Rating": 5, "Description": "The court is covered, so you can play even on rainy days.\n\nThere is a shaded rest area next to the court with fans, tables, and chairs, making it easy to take breaks and interact with other players.\n\nDue to its location, the court attracts many foreigners, giving you the opportunity to connect with people from various countries through pickleball.\n\nThe player mix is well balanced between beginners and intermediate players, so it’s easy to find others at a similar skill level.\n\nThe organizers generally do not intervene in play, so the social rotation relies on the participants’ self-management and mutual respect.\n\nThey offer an unlimited play membership for just 700,000 VND per month, which is a great deal for those who plan to come regularly.\n\nYou can sign up for Social events through Reclub. Spots tend to fill up as early as the day before, so early booking is recommended.", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn24Bq9AYyuYMPfGdW5xqNCwIyOTTXoOUZL_jfQXyEGxU-Ku-KYIM7zQQO0gTOIZPaalS2Ab2CyG0MNDU4kbwIDS6G4nSsywp4styXbQS4WY0RyjZlsCcF8p3sAzmdhsWDEO1ZRuTQLuIy5G=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn0LAn3etXYScNcOUeDQ7N6y3dEh8w-8gpZI4cOqsnb0LRhPysDe-LQHP2V0Y3j4ZYCjeD7F-yHoLA1zZ6_tFk9mYib84g8xNpPAc2xT3gLiarf98IcYawlZZYkhv3_pNzq6Cq_063l66PM=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn0WAcB-N30Q282IPnv5SEQtbdQ1nxNVdrjhuXKIhKmGPCe2V5UL8BFaHDZqDvjfm56kawT9_cKr7T6XrQF2n28bOt-q0Li7JpfiQC2wVuneFVg_gCPawos1ZAF5ioDA1m5d84y_DcGxC8jf=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn2HsBRU0fH1rFs-cPCTrsPmMYdR3TxSCY1rYi1-SSr6Mn0sjOMO7vTu4m7TFZtnindcBvy1DP7lh373ebQbxzNLj-DKbx19s4p29nzaSjxL1qup2y00ym181l8xZ1PanxXcoGJGpUQ4qjdG=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn00J4PQ5CGelYcb_ttS6Pg_8Rf84-Lb1YIviMZ7mYpk8DYtck-67DY85_Glef8LqUQILRyr7_-k_jTVy7hU0boUdbhkAuUuINXdPbNINal3XqGKW6lnVfV-pS9jhPgbfzclZgA4nnDPGO4=k-no"], "When": "2025-7-20"}]'::jsonb, '{"Friday": {"10": 50, "11": 60, "12": 68, "13": 66, "14": 56, "15": 43, "16": 49, "17": 56, "18": 74, "19": 84, "20": 78, "21": 64, "22": 0, "5": 0, "6": 9, "7": 15, "8": 25, "9": 41}, "Monday": {"10": 56, "11": 64, "12": 64, "13": 62, "14": 50, "15": 41, "16": 43, "17": 45, "18": 45, "19": 43, "20": 43, "21": 45, "22": 0, "5": 0, "6": 17, "7": 23, "8": 31, "9": 45}, "Saturday": {"10": 70, "11": 72, "12": 64, "13": 56, "14": 56, "15": 64, "16": 60, "17": 58, "18": 47, "19": 47, "20": 43, "21": 37, "22": 0, "5": 0, "6": 19, "7": 27, "8": 45, "9": 60}, "Sunday": {"10": 49, "11": 49, "12": 56, "13": 49, "14": 41, "15": 39, "16": 50, "17": 72, "18": 78, "19": 80, "20": 74, "21": 58, "22": 0, "5": 0, "6": 21, "7": 37, "8": 47, "9": 49}, "Thursday": {"10": 37, "11": 43, "12": 49, "13": 56, "14": 66, "15": 68, "16": 76, "17": 92, "18": 100, "19": 90, "20": 74, "21": 54, "22": 0, "5": 0, "6": 17, "7": 19, "8": 23, "9": 29}, "Tuesday": {"10": 52, "11": 60, "12": 58, "13": 52, "14": 45, "15": 39, "16": 50, "17": 70, "18": 86, "19": 78, "20": 68, "21": 39, "22": 0, "5": 0, "6": 17, "7": 21, "8": 35, "9": 43}, "Wednesday": {"10": 52, "11": 62, "12": 58, "13": 62, "14": 64, "15": 74, "16": 72, "17": 72, "18": 66, "19": 64, "20": 60, "21": 50, "22": 0, "5": 0, "6": 7, "7": 7, "8": 17, "9": 35}}'::jsonb, '[{"id": "accessibility", "name": "Accessibility", "options": [{"name": "Wheelchair-accessible entrance", "enabled": false}]}, {"id": "amenities", "name": "Amenities", "options": [{"name": "Washroom", "enabled": true}]}]'::jsonb, ARRAY['Sports club', 'Washroom'], NULL, '06:30', '21:30') ON CONFLICT (place_id) DO UPDATE SET name = EXCLUDED.name, address = EXCLUDED.address, city = EXCLUDED.city, district = EXCLUDED.district, lat = EXCLUDED.lat, lng = EXCLUDED.lng, rating = EXCLUDED.rating, rating_count = EXCLUDED.rating_count, phone = EXCLUDED.phone, google_maps_url = EXCLUDED.google_maps_url, booking_url = EXCLUDED.booking_url, thumbnail_url = EXCLUDED.thumbnail_url, images = EXCLUDED.images, opening_hours = EXCLUDED.opening_hours, reviews_data = EXCLUDED.reviews_data, popular_times = EXCLUDED.popular_times, amenities = EXCLUDED.amenities, tags = EXCLUDED.tags, highlight = EXCLUDED.highlight, hours_open = EXCLUDED.hours_open, hours_close = EXCLUDED.hours_close;
