INSERT INTO public.courts (name, address, city, district, lat, lng, rating, rating_count, phone, google_maps_url, booking_url, place_id, thumbnail_url, images, opening_hours, reviews_data, popular_times, amenities, tags, highlight, hours_open, hours_close) VALUES ('Ninja PickleBall', '47 Tôn Thất Đ. Kỵ, Hòa Xuân, Đà Nẵng 550000, Vietnam', 'Da Nang', 'Hoa Xuan', 16.018593, 108.22094, 4.7, 18, NULL, 'https://www.google.com/maps/place/Ninja+PickleBall/data=!4m7!3m6!1s0x31421b000b5bdac3:0xb7eaa44b69fe1fc6!8m2!3d16.0185928!4d108.2209396!16s%2Fg%2F11lzfk63tl!19sChIJw9pbCwAbQjERxh_-aUuk6rc?authuser=0&hl=en&rclk=1', NULL, 'ChIJw9pbCwAbQjERxh_-aUuk6rc', 'https://lh3.googleusercontent.com/gps-cs-s/APNQkAGi3AFhP-i781tYWFSA0Vl6OOZk_GKKPUnKaowps6BCAQC7XfVxZ1fkErUbuP4imBARIHIgQk2MkqnHf8jUZolkkbqMWhRDRqbZ4wBp0BS_Ih3HheL60kluMhkFqnVDpwaXY9qZ=w408-h306-k-no', '[{"title": "All", "image": "https://lh3.googleusercontent.com/gps-cs-s/APNQkAGi3AFhP-i781tYWFSA0Vl6OOZk_GKKPUnKaowps6BCAQC7XfVxZ1fkErUbuP4imBARIHIgQk2MkqnHf8jUZolkkbqMWhRDRqbZ4wBp0BS_Ih3HheL60kluMhkFqnVDpwaXY9qZ=w397-h298-k-no"}, {"title": "Swimming pool", "image": "https://lh3.googleusercontent.com/gps-cs-s/APNQkAGSYlhd0r71esIRi3wTHH-SeOukrB7QeR2TlggBmD7otThkH8DUi_CYSnXsEmlm65UDsfwqUHNRi3vN8-gN73OVpP7oYzjIcGKtTS-NFIFLOa33wT35xOaRJX-IBLREYogZ-hdz=w529-h298-k-no"}, {"title": "Stadium", "image": "https://lh3.googleusercontent.com/gps-cs-s/APNQkAGi3AFhP-i781tYWFSA0Vl6OOZk_GKKPUnKaowps6BCAQC7XfVxZ1fkErUbuP4imBARIHIgQk2MkqnHf8jUZolkkbqMWhRDRqbZ4wBp0BS_Ih3HheL60kluMhkFqnVDpwaXY9qZ=w397-h298-k-no"}, {"title": "Street View & 360°", "image": "https://streetviewpixels-pa.googleapis.com/v1/thumbnail?panoid=P9Icfw0UrRE3xGfQrOWPQw&cb_client=maps_sv.tactile.gps&w=224&h=298&yaw=142.07275&pitch=0&thumbfov=100"}]'::jsonb, '{"Friday": ["5 a.m.–11 p.m."], "Monday": ["5 a.m.–11 p.m."], "Saturday": ["5 a.m.–11 p.m."], "Sunday": ["5 a.m.–11 p.m."], "Thursday": ["5 a.m.–11 p.m."], "Tuesday": ["5 a.m.–11 p.m."], "Wednesday": ["5 a.m.–11 p.m."]}'::jso