oogleusercontent.com/a-/ALV-UjWkqRsBlyL8Z2TjV3Vy7uVgZzcFLbd5A0hoBJ4z0mXli6S809tB=s120-c-rp-mo-br100", "Rating": 5, "Description": "Sân mới, rộng rãi, dịch vụ ổn áp nhé.\nÔng chủ vui tính nhậu được, ae chơi xong rủ ổng làm vài chai thì best lun :)))", "Images": null, "When": ""}, {"Name": "hongvan nguyen", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjVLBXBxaoIotDjeqEvx2jSIZWnQtf-BcNd3oAbYGxGZMB1ZxfU=s120-c-rp-mo-br100", "Rating": 5, "Description": "Sân đẹp, ánh sáng tốt, view đẹp + nhân viên thân thiện nhiệt tình", "Images": null, "When": ""}, {"Name": "Ngọc Tín Võ", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjVDG6-4xr-CrlURMX-Vrh0GwZine8Bl55BOMki46DYxkhMBD4A=s120-c-rp-mo-br100", "Rating": 5, "Description": "Sân mới đẹp, chủ sân nhiệt tình, sẽ ủng hộ thường xuyên", "Images": null, "When": ""}, {"Name": "huong giang Ngo", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjWv0QaHBddN5iisMmuGfWj1a71T2KPh9qYEOxsMNqN06e8D-wZB=s120-c-rp-mo-br100", "Rating": 5, "Description": "Sân mới keng, sạch sẽ. Nhân viên nhiệt tình. Sẽ quay lại nữa ạ🥰", "Images": null, "When": ""}]'::jsonb, '{"Friday": {"10": 24, "11": 17, "12": 13, "13": 17, "14": 22, "15": 22, "16": 35, "17": 42, "18": 51, "19": 57, "20": 51, "21": 37, "22": 28, "4": 0, "5": 22, "6": 24, "7": 28, "8": 37, "9": 33}, "Monday": {"10": 28, "11": 35, "12": 42, "13": 35, "14": 35, "15": 44, "16": 48, "17": 55, "18": 66, "19": 73, "20": 73, "21": 60, "22": 42, "4": 0, "5": 28, "6": 26, "7": 31, "8": 22, "9": 22}, "Saturday": {"10": 35, "11": 26, "12": 24, "13": 31, "14": 37, "15": 64, "16": 75, "17": 91, "18": 77, "19": 62, "20": 48, "21": 42, "22": 31, "4": 0, "5": 22, "6": 35, "7": 26, "8": 33, "9": 31}, "Sunday": {"10": 100, "11": 75, "12": 48, "13": 42, "14": 48, "15": 57, "16": 53, "17": 42, "18": 42, "19": 46, "20": 44, "21": 33, "22": 24, "4": 0, "5": 26, "6": 44, "7": 51, "8": 77, "9": 95}, "Thursday": {"10": 26, "11": 24, "12": 24, "13": 22, "14": 24, "15": 33, "16": 51