INSERT INTO public.courts (name, address, city, district, lat, lng, rating, rating_count, phone, google_maps_url, booking_url, place_id, thumbnail_url, images, opening_hours, reviews_data, popular_times, amenities, tags, highlight, hours_open, hours_close) VALUES ('Silk Sense Premier Pickleball Court', '01 Nguyễn Thành Ý, Cẩm An, Hội An Tây, Đà Nẵng 560000, Vietnam', 'Da Nang', 'Cẩm An, Hoi An Tay', 15.899505, 108.356555, 4.5, 4, '+84 775 914 166', 'https://www.google.com/maps/place/Silk+Sense+Premier+Pickleball+Court/data=!4m7!3m6!1s0x31420d29edd90519:0xe11579fafc5127aa!8m2!3d15.899505!4d108.3565554!16s%2Fg%2F11x2grcrvp!19sChIJGQXZ7SkNQjERqidR_Pp5FeE?authuser=0&hl=en&rclk=1', NULL, 'ChIJGQXZ7SkNQjERqidR_Pp5FeE', 'https://lh3.googleusercontent.com/gps-cs-s/APNQkAEvzy0mFbz9WBrJVPr3t3NB49cTi-YnBXu8XjtAVbl9w_z243oGzhpyGOowz_19L6d8Rk2E8dbQyNAh6FW1noNd802xWRhjT35telFqXdZunbC4uz_mA6o6x3-U_VLYlG4OycmB63NWWb4=w408-h272-k-no', '[{"title": "All", "image": "https://lh3.googleusercontent.com/gps-cs-s/APNQkAEvzy0mFbz9WBrJVPr3t3NB49cTi-YnBXu8XjtAVbl9w_z243oGzhpyGOowz_19L6d8Rk2E8dbQyNAh6FW1noNd802xWRhjT35telFqXdZunbC4uz_mA6o6x3-U_VLYlG4OycmB63NWWb4=w447-h298-k-no"}, {"title": "By owner", "image": "https://lh3.googleusercontent.com/gps-cs-s/APNQkAF7csV2c8lAL47Ju2plIfPPbh5J5j8vSYo7RgMjLlnSDJsObA7HCAVF27bqwD5YBeXbsFuHa_xieORV0bce-AAvN8vaLIl30X4M3sGJgTBuRuRhDQISIgqcWH3WJLZabolGCRs9=w447-h298-k-no"}, {"title": "Videos", "image": "https://lh3.googleusercontent.com/gps-cs-s/APNQkAGkf3z4z0CHpE_X9lhEouKsQWUEEJ0GHZ-nBYvwfBJ0eEu0jeCSLI95xtumaxxQO6t-1p2iE49fU_BCnB8Rld5QAoREPPbVTbClbRL1DkD3B9fZlBAKORIL9Hw70-cNHcP8RrQLi49G7IgJ=w224-h497-k-no"}, {"title": "Street View & 360°", "image": "https://streetviewpixels-pa.googleapis.com/v1/thumbnail?panoid=GqjSDFdgWtQAcwh_685MTw&cb_client=maps_sv.tactile.gps&w=224&h=298&yaw=208.93323&pitch=0&thumbfov=100"}]'::jsonb, '{"Friday": ["5 a.m.–10 p.m."], "Monday": ["5 a.m.–10 p.m."], "Saturday": ["5 a.m.–10 p.m."], "Sunday": ["5 a.m.–10 p.m."], "Thursday": ["5 a.m.–10 p.m."], "Tuesday": ["5 a.m.–10 p.m."], "Wednesday": ["5 a.m.–10 p.m."]}'::jsonb, '[{"Name": "Stephen Belenky", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjU2ZK7O-Z55x9aaHOugavVA-qivoZUJKKQt0YhhaBMJEaBXm8Eq=s120-c-rp-mo-ba2-br100", "Rating": 3, "Description": "We''ve been coming here regularly and playing for several hours each time. The court itself is solid, and we’ve always appreciated it''s scenic location and relatively laid back atmosphere.\n\nUnfortunately, our experience last night was disappointing, and for a place that wants to build community around the sport, this felt like a real miss.\n\nThere was no staff on duty. Only a hotel security guard managing the courts. That alone created a tense dynamic. One of our players rented a paddle (not once, but twice after the first one broke). Both paddles cracked during normal play. He felt awful, but the truth is, that’s part of the risk when you rent out equipment that’s been used hundreds of times. Instead of handling it with care or curiosity, the security guard berated him and then charged 400,000 VND (200k per paddle). On top of that, he checked our bags without permission and accused us of taking paddles and balls, even though we brought our own.\n\nWe understand there are cultural differences when it comes to hospitality and accountability. But here’s the bigger picture: When you rent out courts and gear, the wear and tear of that gear is part of your business model. Charging guests for broken paddles without assessing prior damage or showing any goodwill misses the point of customer care. More importantly, outsourcing customer service to a security guard (someone trained to enforce, not to host) puts your guests in a vulnerable position.\n\nWe were genuinely sad to have this kind of interaction. We hope management reconsiders how the court is staffed and how situations like this are handled going forward. Hoi An deserves better pickleball experiences, and this could still be one of them.", "Images": null, "When": ""}, {"Name": "Haein Cho", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjX_zfPCz7G_mlnBTei1ro01l_ZPrBslnz6B7ztid9Rqt0UPVjYN=s120-c-rp-mo-ba5-br100", "Rating": 5, "Description": "- 실크센스에서 투숙하면서 1hr 피클볼 레슨 받음. 코치님 정말 친절하시고 피클볼은 처음 쳐봤는데 너무너무 재밌었음 !! 초심자도 알기 쉽게 설명해주시는데 인내심이 정말 대단하심 .. 머쓱 ..\n- 레슨 안받아도 예약하면 이용할 수 있는 것으로 보임\n\n실크센스 투숙한다면 레슨 시간 맞춰서 한 번 가보시길 추천드립니다🤗 처음 보는 운동인데 나름 재밌더라구요 !", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn1l920CtqB9UQHPCMjBl1E1edwHyzgO5qYVE3xJVfTpqtibGTUmaGmNHOpLcK8UxpHYt2MIy-b8OhLv5y-Z0UpS4A3HpzEYpiJ9uSrs1KgylzXfYDF-9F78ftVDW_XMhN9PPEDV=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn0dEzexSJB_QB15p9cmIXaC5SpeTafPIMTyFLxHtEewYIkP8Fqx_W-fn6f_8SW4fTvKMJIO0hG6_8FfQKnLgNRC9LGlte1IUb1T6p8nOEPxChiU1XDA1-kaLNh6BHL8zFqpFBH8Uw=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn30qrrxa7s3jc5UEKW3RRF-COGlfypS_J434k6zkvtRlxbF3cP6ygDG1-_hRUBauSO_2gkiOTPLcitM64br35f1z9HXt7wedBBT_BRnVMGCzpRtoOZlgL0zHbBMmjouyNY4zKwQ=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn2rnj5LyZ5nPD8y8iYe9cHpdZtQZSlDKVfOKB3II5vhjUMl5bWS1oplt1Rv_L0eyvFpS-2WgFClXDlFOKw45MtGl2t_j9dvIpzrmBdmbZhYf-4pxzsqRC63AeZNZr3imgx63RlviA=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn0TaewkxDM59mJXfJz9wI9HAGj6ALXQgByFU4kRA3PaGjaG7tI98I6HUKaAPvi3pmRDzvFdlgFgCsD6pVJ9JtDV2cAya3aG6Y8ojJdIsSi7lqUMP3DpPtWPkuJuV8hjNVQ0U6zn=k-no"], "When": "2025-4-30"}, {"Name": "Bùi Quang Hà", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjVdn1LNcG1WrAbYqL0DQU-jJZIt3lQNyHlVJQGc_CjMFMy4AlSB=s120-c-rp-mo-br100", "Rating": 5, "Description": "Sân mới, đồ ăn chất lượng", "Images": null, "When": ""}, {"Name": "Ngô Hồ Hạ", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjXp-j59Faw4-o2Anoc2JmKMtsxHapO_abVoOikwbyYS_fXUjvoy=s120-c-rp-mo-ba5-br100", "Rating": 5, "Description": "", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn1wXJTFGlfEMREmhBHTD2H-pNs5jKwkVJYr3UUaMb_kiA8Rjp7ms2T383XNe-S1qxfl1